@startuml
skinparam classAttributeIconSize 0

class Artisan {
  salaire
  coordonnee
  --
  getPaye()
}

class Chantier {
  dateD
  dateF
  adresse
  --
  getAdresse()
  affecterArtisan()
}

class Travailler {
  nbHeure
  debMission
  finMission
  --
  calculerPaye()
}

Artisan "1..*" -- "0..*" Chantier
Travailler .. Artisan--Chantier
@enduml
